"""Shared data-loading and attribution logic for the malfunction analysis."""
import csv, glob
from collections import defaultdict

def to_min(day, hhmm):
    h, m = hhmm.split(':')
    return day * 1440 + int(h) * 60 + int(m)

def load_events():
    events = []
    for path in glob.glob('raw_service_reports/day_*/*.txt'):
        d = {}
        for line in open(path):
            line = line.strip()
            if ':' in line:
                k, v = line.split(':', 1)
                d[k.strip()] = v.strip()
        day = int(d['DAY'])
        events.append(dict(day=day, wo=d['WORK ORDER'], machine=d['MACHINE'],
            tech=d['TECHNICIAN'], wtype=d['WORK TYPE'], reason=d['REPORTED REASON'],
            started=d['STARTED'], completed=d['COMPLETED'],
            start_min=to_min(day, d['STARTED']), comp_min=to_min(day, d['COMPLETED']),
            path=path))
    return events

def load_batches():
    mal = {}
    for r in csv.DictReader(open('machine_assignment_log.csv')):
        mal[r['job_id']] = r
    batches = {}
    for r in csv.DictReader(open('production_batches.csv')):
        b = r['batch_id']; j = r['job_id']
        st = mal[j]['start_time']
        batches[b] = dict(batch_id=b, day=int(r['production_day']), job=j,
            machine=r['machine_id'], product=r['product_id'],
            qty=int(r['produced_quantity']), start_min=to_min(int(r['production_day']), st),
            start_time=st, seq=int(mal[j]['sequence_on_machine']))
    return batches

def load_inspections():
    qi = {}
    for r in csv.DictReader(open('quality_inspections.csv')):
        qi[r['batch_id']] = dict(batch_id=r['batch_id'], product=r['product_id'],
            inspected=int(r['inspected_quantity']), rejected=int(r['rejected_quantity']),
            rejected_pct=float(r['rejected_pct']), defect=r['defect_code'],
            result=r['inspection_result'], inspection_day=int(r['inspection_day']))
    return qi

def load_products():
    prod = {}
    for r in csv.DictReader(open('products.csv')):
        prod[r['product_id']] = dict(family=r['product_family'],
            nominal=int(r['nominal_batch_size']),
            threshold=float(r['quality_rejection_threshold_pct']))
    return prod

def machine_intervals(events):
    """Return events grouped by machine, sorted by completion time."""
    by_machine = defaultdict(list)
    for e in events:
        by_machine[e['machine']].append(e)
    for m in by_machine:
        by_machine[m].sort(key=lambda e: (e['comp_min'], e['start_min']))
    return by_machine

def attribute(batch, by_machine):
    """Return the maintenance event whose interval contains this batch, or None.
    Interval of event e: production started after e.completed and before next event's start."""
    m = batch['machine']
    evs = by_machine.get(m, [])
    chosen = None
    for i, e in enumerate(evs):
        if batch['start_min'] > e['comp_min']:
            nxt = evs[i + 1] if i + 1 < len(evs) else None
            if nxt is None or batch['start_min'] < nxt['start_min']:
                chosen = e
    return chosen

