"""Full attribution pipeline with configurable fault classification."""
from lib import *
from collections import defaultdict
import numpy as np

events = load_events(); batches = load_batches(); qi = load_inspections(); prod = load_products()
by_machine = machine_intervals(events)
wo_event = {e['wo']: e for e in events}

# natural anchor per product from accepted batches
acc = defaultdict(list)
for b, info in batches.items():
    if qi[b]['result'] == 'ACCEPTED':
        acc[info['product']].append(qi[b]['rejected_pct'])
am = {p: float(np.mean(v)) for p, v in acc.items()}
asd = {p: float(np.std(v)) for p, v in acc.items()}

# attribute every batch to its interval (wo)
batch_wo = {}
for b, info in batches.items():
    e = attribute(info, by_machine)
    batch_wo[b] = e['wo'] if e else None

# build cells: (wo, product) -> list of batch_ids
cell = defaultdict(list)
for b, info in batches.items():
    if batch_wo[b]:
        cell[(batch_wo[b], info['product'])].append(b)

def zof(b):
    info = batches[b]; p = info['product']
    return (qi[b]['rejected_pct'] - am[p]) / asd[p]

def cell_stats(key):
    bs = cell[key]
    n = len(bs)
    rej = [b for b in bs if qi[b]['result'] == 'REJECTED']
    maxz = max((zof(b) for b in bs), default=0.0)
    return n, len(rej), maxz, rej

def fault_cells(z_single=7.0, z_multi=5.0):
    """Return set of (wo,product) cells judged faulty.
    A cell is faulty if it has >=1 rejection AND either:
      - it is fully rejected with n>=2 and maxz>=z_multi (rate+magnitude), or
      - it has >=2 rejections and maxz>=z_multi, or
      - its max batch z >= z_single (a single extreme batch)."""
    out = {}
    for key in cell:
        n, k, maxz, rej = cell_stats(key)
        if k == 0:
            continue
        faulty = False
        if k >= 2 and maxz >= z_multi:
            faulty = True
        elif n >= 2 and k == n and maxz >= z_multi:
            faulty = True
        elif maxz >= z_single:
            faulty = True
        if faulty:
            out[key] = (n, k, maxz, rej)
    return out

def confirm(fcells, min_batches=3, min_wos=2):
    """Aggregate fault-rejected batches by technician; confirm and report products."""
    tech_batches = defaultdict(set)   # tech -> set of rejected batch_ids
    tech_wos = defaultdict(set)       # tech -> set of wos
    tech_prod_batches = defaultdict(lambda: defaultdict(set))  # tech -> product -> batches
    for (wo, p), (n, k, maxz, rej) in fcells.items():
        tech = wo_event[wo]['tech']
        for b in rej:
            tech_batches[tech].add(b)
            tech_wos[tech].add(wo)
            tech_prod_batches[tech][p].add(b)
    confirmed = {}
    for tech, bs in tech_batches.items():
        if len(bs) >= min_batches and len(tech_wos[tech]) >= min_wos:
            confirmed[tech] = {p: len(v) for p, v in tech_prod_batches[tech].items()}
    return confirmed, tech_batches, tech_wos

def product_answer(confirmed):
    prod_techs = defaultdict(set)
    for tech, prods in confirmed.items():
        for p in prods:
            prod_techs[p].add(tech)
    return {p: sorted(prod_techs[p]) for p in sorted(prod_techs)}

if __name__ == '__main__':
    import json, sys
    fc = fault_cells()
    confirmed, tb, tw = confirm(fc)
    print("Confirmed technicians:", len(confirmed))
    for t in sorted(confirmed):
        print(f"  {t}: batches={len(tb[t])} wos={len(tw[t])} products={confirmed[t]}")
    ans = product_answer(confirmed)
    print("\nProduct answer:")
    print(json.dumps(ans, indent=0))

