# Sensitivity to attribution boundary: re-attribute using next.comp_min instead of next.start_min
from lib import *
events=load_events(); batches=load_batches(); qi=load_inspections()
import numpy as np
from collections import defaultdict
by_machine=machine_intervals(events); wo_event={e['wo']:e for e in events}
acc=defaultdict(list)
for b,i in batches.items():
    if qi[b]['result']=='ACCEPTED': acc[i['product']].append(qi[b]['rejected_pct'])
nm={p:np.mean(v) for p,v in acc.items()}; ns={p:np.std(v) for p,v in acc.items()}
def attr_comp(info):
    evs=by_machine.get(info['machine'],[]); chosen=None
    for i,e in enumerate(evs):
        if info['start_min']>e['comp_min']:
            nxt=evs[i+1] if i+1<len(evs) else None
            if nxt is None or info['start_min']<nxt['comp_min']:   # boundary = next completion
                chosen=e
    return chosen
cell=defaultdict(list)
for b,info in batches.items():
    e=attr_comp(info)
    if e: cell[(e['wo'],info['product'])].append(b)
tb=defaultdict(set);tw=defaultdict(set);tp=defaultdict(lambda:defaultdict(set))
for (wo,p),bs in cell.items():
    rej=[b for b in bs if qi[b]['result']=='REJECTED']
    if not rej: continue
    if max((qi[b]['rejected_pct']-nm[p])/ns[p] for b in bs)<7.0: continue
    t=wo_event[wo]['tech']
    for b in rej: tb[t].add(b); tw[t].add(wo); tp[t][p].add(b)
conf={t for t in tb if len(tb[t])>=3 and len(tw[t])>=2}
pt=defaultdict(set)
for t in conf:
    for p in tp[t]: pt[p].add(t)
alt={p:sorted(pt[p]) for p in sorted(pt)}
print("\nBoundary=next.completion gives identical answer:", alt==a)
